  "text": "func (b *backend) instanceIamRoleARN(iamClient *iam.IAM, instanceProfileName string) (string, error) {
n1: 	if iamClient == nil {
n2: 		return "", fmt.Errorf("nil iamClient")
	}
n3: 	if instanceProfileName == "" {
n4: 		return "", fmt.Errorf("missing instance profile name")
	}

n5: 	profile, err := iamClient.GetInstanceProfile(&iam.GetInstanceProfileInput{
		InstanceProfileName: aws.String(instanceProfileName),
	})
n6: 	if err != nil {
n7: 		return "", awsutil.AppendAWSError(err)
	}
n8: 	if profile == nil {
n9: 		return "", fmt.Errorf("nil output while getting instance profile details")
	}

n10: 	if profile.InstanceProfile == nil {
n11: 		return "", fmt.Errorf("nil instance profile in the output of instance profile details")
	}

n12: 	if profile.InstanceProfile.Roles == nil || len(profile.InstanceProfile.Roles) != 1 {
n13: 		return "", fmt.Errorf("invalid roles in the output of instance profile details")
	}

n14: 	if profile.InstanceProfile.Roles[0].Arn == nil {
n15: 		return "", fmt.Errorf("nil role ARN in the output of instance profile details")
	}

n16: 	return *profile.InstanceProfile.Roles[0].Arn, nil
}
"
}

